п»ї#!/bin/bash# ============================================================# UCANJUSCHILL Гўв‚¬вЂќ Full GCP Launch Script# Julius Cameron Hill IP# Run once. Launches everything.# ============================================================set -ePROJECT_ID="ucanjuschill-prod"REGION="us-central1"ZONE="us-central1-a"CLUSTER="ucanjuschill-cluster"DOMAIN="ucanjuschill.com"BILLING_ACCOUNT=$(gcloud beta billing accounts list --format="value(name)" --limit=1)echo "Г°ЕёЕЎв‚¬ UCANJUSCHILL FULL LAUNCH"echo "================================"# ГўвЂќв‚¬ГўвЂќв‚¬ STEP 1: Create & configure project ГўвЂќв‚¬ГўвЂќв‚¬echo "[1/8] Creating GCP project..."gcloud projects create $PROJECT_ID --name="UcanJusChill" 2>/dev/null || echo "Project exists, continuing..."gcloud config set project $PROJECT_ID# Link billing (uses your credits)echo "[2/8] Linking billing account..."gcloud beta billing projects link $PROJECT_ID --billing-account=$BILLING_ACCOUNT# ГўвЂќв‚¬ГўвЂќв‚¬ STEP 2: Enable all APIs ГўвЂќв‚¬ГўвЂќв‚¬echo "[3/8] Enabling APIs..."gcloud services enable \  container.googleapis.com \  sqladmin.googleapis.com \  storage.googleapis.com \  secretmanager.googleapis.com \  artifactregistry.googleapis.com \  cloudbuild.googleapis.com \  run.googleapis.com \  aiplatform.googleapis.com \  --project=$PROJECT_ID# ГўвЂќв‚¬ГўвЂќв‚¬ STEP 3: Create Artifact Registry (Docker images) ГўвЂќв‚¬ГўвЂќв‚¬echo "[4/8] Creating Artifact Registry..."gcloud artifacts repositories create ucanjuschill \  --repository-format=docker \  --location=$REGION \  --description="UcanJusChill images" 2>/dev/null || echo "Registry exists."# ГўвЂќв‚¬ГўвЂќв‚¬ STEP 4: Create GKE Cluster ГўвЂќв‚¬ГўвЂќв‚¬echo "[5/8] Creating GKE cluster (uses ~$80/mo from credits)..."gcloud container clusters create $CLUSTER \  --zone=$ZONE \  --num-nodes=2 \  --machine-type=e2-standard-2 \  --enable-autoscaling \  --min-nodes=2 \  --max-nodes=5 \  --workload-pool=$PROJECT_ID.svc.id.goog \  --enable-ip-alias 2>/dev/null || echo "Cluster exists."gcloud container clusters get-credentials $CLUSTER --zone=$ZONE# ГўвЂќв‚¬ГўвЂќв‚¬ STEP 5: Cloud SQL (Postgres) ГўвЂќв‚¬ГўвЂќв‚¬echo "[6/8] Creating Cloud SQL Postgres..."gcloud sql instances create ucanjuschill-db \  --database-version=POSTGRES_15 \  --tier=db-f1-micro \  --region=$REGION \  --storage-auto-increase 2>/dev/null || echo "DB exists."gcloud sql databases create ucanjuschill --instance=ucanjuschill-db 2>/dev/null || truegcloud sql users create appuser \  --instance=ucanjuschill-db \  --password=$(openssl rand -base64 24) 2>/dev/null || true# ГўвЂќв‚¬ГўвЂќв‚¬ STEP 6: Cloud Storage (HLS video chunks) ГўвЂќв‚¬ГўвЂќв‚¬echo "[7/8] Creating storage buckets..."gsutil mb -l $REGION gs://$PROJECT_ID-hls 2>/dev/null || truegsutil mb -l $REGION gs://$PROJECT_ID-assets 2>/dev/null || truegsutil iam ch allUsers:objectViewer gs://$PROJECT_ID-hlsgsutil iam ch allUsers:objectViewer gs://$PROJECT_ID-assets# ГўвЂќв‚¬ГўвЂќв‚¬ STEP 7: Store secrets in Secret Manager ГўвЂќв‚¬ГўвЂќв‚¬echo "[8/8] Setting up secrets..."echo "Generating secure secrets..."JWT_SECRET=$(openssl rand -base64 48)REDIS_PASS=$(openssl rand -base64 24)DB_PASS=$(openssl rand -base64 24)echo -n "$JWT_SECRET"  | gcloud secrets create jwt-secret --data-file=- 2>/dev/null || \  echo -n "$JWT_SECRET" | gcloud secrets versions add jwt-secret --data-file=-echo -n "$REDIS_PASS"  | gcloud secrets create redis-password --data-file=- 2>/dev/null || \  echo -n "$REDIS_PASS" | gcloud secrets versions add redis-password --data-file=-echo -n "$DB_PASS"     | gcloud secrets create db-password --data-file=- 2>/dev/null || \  echo -n "$DB_PASS" | gcloud secrets versions add db-password --data-file=-# ГўвЂќв‚¬ГўвЂќв‚¬ STEP 8: CI/CD Гўв‚¬вЂќ Cloud Build trigger ГўвЂќв‚¬ГўвЂќв‚¬echo "Setting up CI/CD pipeline..."gcloud builds triggers create github \  --repo-name=ucanjuschill \  --repo-owner=juliushill42 \  --branch-pattern="^main$" \  --build-config=cloudbuild.yaml \  --project=$PROJECT_ID 2>/dev/null || echo "Trigger exists."echo ""echo "ГўЕ“вЂ¦ INFRASTRUCTURE LIVE"echo "================================"echo "Project:  $PROJECT_ID"echo "Cluster:  $CLUSTER ($ZONE)"echo "Database: ucanjuschill-db"echo "Storage:  gs://$PROJECT_ID-hls"echo "Registry: $REGION-docker.pkg.dev/$PROJECT_ID/ucanjuschill"echo ""echo "NEXT: Run deploy.sh to push your containers"